import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"香港与新加坡账户对比","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/hk-vs-sg.md","filePath":"zh-CN/account/hk-vs-sg.md"}'),l={name:"account/hk-vs-sg.md"};function o(i,t,n,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="香港与新加坡账户对比" tabindex="-1">香港与新加坡账户对比 <a class="header-anchor" href="#香港与新加坡账户对比" aria-label="Permalink to &quot;香港与新加坡账户对比&quot;">​</a></h1><p>长桥提供香港综合账户和新加坡综合账户两种账户，一个客户可以同时持有两个账户。</p><h2 id="核心差异一览" tabindex="-1">核心差异一览 <a class="header-anchor" href="#核心差异一览" aria-label="Permalink to &quot;核心差异一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>香港综合账户</th><th>新加坡综合账户</th></tr></thead><tbody><tr><td>账户编号前缀</td><td>H（如 H12345678）</td><td>SG（如 SG12345678）</td></tr><tr><td>监管机构</td><td>香港证监会（SFC）</td><td>新加坡金融管理局（MAS）</td></tr><tr><td>开户时效</td><td>3–5 个工作日</td><td>2–5 个工作日</td></tr><tr><td>主要面向人群</td><td>香港居民、中国大陆居民</td><td>中国大陆居民、东南亚居民（含新加坡）</td></tr><tr><td>港股交易</td><td>✓</td><td>✓</td></tr><tr><td>美股交易</td><td>✓</td><td>✓</td></tr><tr><td>新加坡股票</td><td>—</td><td>✓</td></tr><tr><td>港元账户</td><td>✓</td><td>—</td></tr><tr><td>美元账户</td><td>✓</td><td>✓</td></tr><tr><td>新加坡元账户</td><td>—</td><td>✓</td></tr><tr><td>融资融券</td><td>✓</td><td>✓</td></tr><tr><td>美股期权</td><td>✓</td><td>✓</td></tr><tr><td>余额通</td><td>✓（香港余额通）</td><td>✓（新加坡余额通）</td></tr></tbody></table><h2 id="入金方式差异" tabindex="-1">入金方式差异 <a class="header-anchor" href="#入金方式差异" aria-label="Permalink to &quot;入金方式差异&quot;">​</a></h2><p><strong>香港综合账户</strong>：FPS 转数快、eDDA、网银转账、银证转账、ATM 与柜台、信用卡入金、电汇</p><p><strong>新加坡综合账户</strong>：PayNow、DDA、网银与电汇、Wise</p><h2 id="如何选择" tabindex="-1">如何选择 <a class="header-anchor" href="#如何选择" aria-label="Permalink to &quot;如何选择&quot;">​</a></h2><p><strong>适合开香港账户</strong>：</p><ul><li>持有香港银行卡，希望通过 FPS / eDDA 便捷入金</li><li>主要交易港股</li><li>已在香港居住或工作</li></ul><p><strong>适合开新加坡账户</strong>：</p><ul><li>在新加坡居住或工作，可使用 PayNow 即时入金</li><li>希望交易新加坡本地股票</li><li>大陆居民但持有新加坡或其他海外身份证件</li></ul><p><strong>同时开两个账户</strong>：</p><ul><li>希望交易港股、美股和新加坡股票</li><li>希望分散账户资产至不同监管框架下</li></ul><h2 id="同时持有两个账户" tabindex="-1">同时持有两个账户 <a class="header-anchor" href="#同时持有两个账户" aria-label="Permalink to &quot;同时持有两个账户&quot;">​</a></h2><p>一个客户可以同时申请并使用两个账户，资金相互独立。如需在两个账户之间划转资金，可通过「资金划转与换汇」中的跨账号划转功能操作。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/account/开通香港综合账户">开通香港综合账户</a></li><li><a href="/account/开通新加坡综合账户">开通新加坡综合账户</a></li><li><a href="/transfers-and-fx/跨账号划转">跨账号划转</a></li></ul>',18)])])}const _=d(l,[["render",o]]);export{p as __pageData,_ as default};
